  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import { ActionPanel } from './components/action_panel/action_panel';
  3→import { CommandPalette } from './components/command_palette/command_palette';
  4→import { Detail } from './components/detail/detail';
  5→import { DetailMetadata } from './components/detail/detail_metadata';
  6→import { EmptyState } from './components/empty_state/empty_state';
  7→import { Kbd } from './components/kbd/kbd';
  8→import { List, ListItem, ListSection } from './components/list';
  9→import type { BreadcrumbItem } from './components/search_bar/search_bar';
 10→import { SearchBar } from './components/search_bar/search_bar';
 11→import { ToastContainer } from './components/toast/toast_container';
 12→import { MOCK_SECTIONS } from './data/mock_data';
 13→import { useToast } from './hooks/use_toast';
 14→import type { ListItemData, ListItemMetadataEntry, SectionData } from './types';
 15→
 16→function filterSections(sections: SectionData[], query: string): SectionData[] {
 17→  if (!query) return sections;
 18→  const lower = query.toLowerCase();
 19→  return sections
 20→    .map(section => ({
 21→      ...section,
 22→      items: section.items.filter(
 23→        item =>
 24→          item.title.toLowerCase().includes(lower) ||
 25→          item.subtitle?.toLowerCase().includes(lower),
 26→      ),
 27→    }))
 28→    .filter(section => section.items.length > 0);
 29→}
 30→
 31→function flattenItems(sections: SectionData[]): ListItemData[] {
 32→  return sections.flatMap(s => s.items);
 33→}
 34→
 35→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 36→  switch (entry.type) {
 37→    case 'label':
 38→      return (
 39→        <DetailMetadata.Label
 40→          key={index}
 41→          title={entry.title}
 42→          text={entry.text}
 43→        />
 44→      );
 45→    case 'link':
 46→      return (
 47→        <DetailMetadata.Link
 48→          key={index}
 49→          title={entry.title}
 50→          text={entry.text}
 51→          target={entry.target}
 52→        />
 53→      );
 54→    case 'tag-list':
 55→      return (
 56→        <DetailMetadata.TagList key={index} title={entry.title}>
 57→          {entry.tags.map(tag => (
 58→            <DetailMetadata.Tag
 59→              key={tag.text}
 60→              text={tag.text}
 61→              color={tag.color}
 62→            />
 63→          ))}
 64→        </DetailMetadata.TagList>
 65→      );
 66→    case 'separator':
 67→      return <DetailMetadata.Separator key={index} />;
 68→  }
 69→}
 70→
 71→function SearchIcon() {
 72→  return (
 73→    <svg
 74→      width="48"
 75→      height="48"
 76→      viewBox="0 0 48 48"
 77→      fill="none"
 78→      xmlns="http://www.w3.org/2000/svg"
 79→    >
 80→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 81→      <line
 82→        x1="30"
 83→        y1="30"
 84→        x2="42"
 85→        y2="42"
 86→        stroke="currentColor"
 87→        strokeWidth="3"
 88→        strokeLinecap="round"
 89→      />
 90→    </svg>
 91→  );
 92→}
 93→
 94→export function App() {
 95→  const [query, setQuery] = useState('');
 96→  const [selectedIndex, setSelectedIndex] = useState(0);
 97→  const [actionsOpen, setActionsOpen] = useState(false);
 98→  const [drilledItem, setDrilledItem] = useState<ListItemData | null>(null);
 99→  const { toasts, show: showToast, hide: hideToast } = useToast();
100→
101→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
102→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
103→  const selectedItem = drilledItem ?? allItems[selectedIndex];
104→
105→  const handleQueryChange = useCallback((value: string) => {
106→    setQuery(value);
107→    setSelectedIndex(0);
108→    setActionsOpen(false);
109→  }, []);
110→
111→  const handleActiveIndexChange = useCallback((index: number) => {
112→    setSelectedIndex(index);
113→    setActionsOpen(false);
114→  }, []);
115→
116→  const handleDrillIn = useCallback(() => {
117→    const item = allItems[selectedIndex];
118→    if (item) {
119→      setDrilledItem(item);
120→      setQuery('');
121→      setActionsOpen(false);
122→      showToast({
123→        style: 'success',
124→        title: `Opened ${item.title}`,
125→      });
126→    }
127→  }, [
128→    allItems,
129→    selectedIndex,
130→    showToast,
131→  ]);
132→
133→  const handleDrillBack = useCallback(() => {
134→    setDrilledItem(null);
135→    setQuery('');
136→    setSelectedIndex(0);
137→    setActionsOpen(false);
138→  }, []);
139→
140→  const breadcrumbs: BreadcrumbItem[] | undefined = drilledItem
141→    ? [
142→        {
143→          label: 'Raycast',
144→          onBack: handleDrillBack,
145→        },
146→        {
147→          label: drilledItem.title,
148→        },
149→      ]
150→    : undefined;
151→
152→  const toggleActions = useCallback(() => {
153→    setActionsOpen(prev => !prev);
154→  }, []);
155→
156→  const closeActions = useCallback(() => {
157→    setActionsOpen(false);
158→  }, []);
159→
160→  useEffect(() => {
161→    function handleKeyDown(e: KeyboardEvent) {
162→      if (e.key === 'k' && e.metaKey) {
163→        e.preventDefault();
164→        setActionsOpen(prev => !prev);
165→      }
166→    }
167→
168→    window.addEventListener('keydown', handleKeyDown);
169→    return () => window.removeEventListener('keydown', handleKeyDown);
170→  }, []);
171→
172→  const detail = selectedItem?.detail;
173→
174→  const dropdownActions = useMemo(
175→    () => [
176→      {
177→        label: 'Open',
178→        shortcut: <Kbd keys={['↵']} />,
179→        onClick: () => {
180→          if (selectedItem) {
181→            showToast({
182→              style: 'success',
183→              title: `Opened ${selectedItem.title}`,
184→            });
185→          }
186→        },
187→      },
188→      {
189→        label: 'Copy Name',
190→        shortcut: (
191→          <Kbd
192→            keys={[
193→              '⌘',
194→              'C',
195→            ]}
196→          />
197→        ),
