      onMouseEnter={handleMouseEnter}
      onClick={onClick}
    >
      {icon && <span className="grid-item__icon">{icon}</span>}
      <span className="grid-item__title">{title}</span>
      {subtitle && <span className="grid-item__subtitle">{subtitle}</span>}
    </div>
  );
}

