@use '../../../styles/tokens' as *;

.grid-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: $space-2;
  padding: $space-3;
  border-radius: $radius-md;
  cursor: pointer;
  border: 2px solid transparent;
  transition:
    transform $transition-fast ease,
    border-color $transition-fast ease,
